import java.util.*

fun solve(m: Long, n: Long, waitCost: Array<Array<Long>>): Long {
    val rows = m.toInt()
    val cols = n.toInt()
    val distOdd = Array(rows) { Array(cols) { Long.MAX_VALUE } }
    val distEven = Array(rows) { Array(cols) { Long.MAX_VALUE } }
    distOdd[0][0] = 1L

    val pq = PriorityQueue<Triple<Long, Int, Int, Int>>(Comparator { a, b ->
        a.first.compareTo(b.first)
    })
    pq.add(Triple(1L, 0, 0, 1))

    while (pq.isNotEmpty()) {
        val (cost, i, j, parity) = pq.poll()

        if (i == rows - 1 && j == cols - 1) {
            return cost
        }

        if (parity == 1 && cost > distOdd[i][j]) {
            continue
        } else if (parity == 0 && cost > distEven[i][j]) {
            continue
        }

        if (parity == 1) {
            val directions = arrayOf(intArrayOf(0, 1), intArrayOf(1, 0))
            for (dir in directions) {
                val ni = i + dir[0]
                val nj = j + dir[1]
                if (ni in 0..rows-1 && nj in 0..cols-1) {
                    val newCost = cost + (ni + 1) * (nj + 1)
                    if (newCost < distEven[ni][nj]) {
                        distEven[ni][nj] = newCost
                        pq.add(Triple(newCost, ni, nj, 0))
                    }
                }
            }
        } else {
            val newCost = cost + waitCost[i][j]
            if (newCost < distOdd[i][j]) {
                distOdd[i][j] = newCost
                pq.add(Triple(newCost, i, j, 1))
            }
        }
    }

    return Long.MAX_VALUE
}
